        rect.name = boundsList.length > 1 ? `Strike Highlight ${index + 1}` : "Strike Highlight";
        placeTextHighlightRectBehindNode(highlightParent, rect, anchorNodeId, nodeIndex >= 0 ? nodeIndex + index : -1);
        rects.push(rect);
